func guidesForErrorPage(code string) map[string]errorGuide {
	guides := map[string]errorGuide{"en": errorPageGuides[code]}
	for language, byCode := range localizedErrorPageGuides {
		if guide, ok := byCode[code]; ok {
			guides[language] = guide
		}
	}
	return guides
}
